// app/components/Author/Author.tsx
import Image from "next/image";
import Link from "next/link";

export interface AuthorData {
  author_name: string;
  credentials?: string;
  author_country?: string;
  avatar?: string;
}

export interface AuthorProps {
  author?: AuthorData;
  content?: string;
  config?: any;
  showAvatar?: boolean;
  showCredentials?: boolean;
  showCountry?: boolean;
  className?: string;
}

export function Author({
  author,
  content,
  config,
  showAvatar = true,
  showCredentials = true,
  showCountry = true,
  className = "",
}: AuthorProps) {
  // Helper function to render the shared template
  const renderAuthorTemplate = (
    authorName: string,
    credentials: string,
    country: string,
    field: string,
    authorImage: string | null
  ) => {
    // Create URL slug from author name
    const authorSlug = authorName
      .toLowerCase()
      .replace(/[^a-z0-9\s-]/g, '') // Remove special characters
      .replace(/\s+/g, '-') // Replace spaces with hyphens
      .replace(/-+/g, '-') // Replace multiple hyphens with single
      .trim();

    return (
      <Link 
        href={`/author/${authorSlug}`}
        className="block hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg p-3 transition-colors duration-200 cursor-pointer"
      >
        <div className={`author-component ${className}`}>
          <table className="w-full">
            <tbody>
              <tr>
                <td className="w-20 pr-4 align-top">
                  {showAvatar && authorImage && (
                    <div className="author-avatar">
                      <Image
                        src={authorImage}
                        alt={authorName || "Author"}
                        width={60}
                        height={60}
                        className="rounded-full"
                      />
                    </div>
                  )}
                </td>
                <td className="align-top">
                  <div className="author-info">
                    {authorName && (
                      <div className="author-name font-medium text-gray-900 dark:text-white block">
                        {authorName}
                      </div>
                    )}

                    {showCredentials && credentials && (
                      <div className="author-credentials text-sm text-gray-600 dark:text-gray-400">
                        {credentials}
                      </div>
                    )}

                    {field && (
                      <div className="author-field text-sm text-gray-600 dark:text-gray-400">
                        {field}
                      </div>
                    )}

                    {showCountry && country && (
                      <div className="author-country text-xs text-gray-500 dark:text-gray-500">
                        {country}
                      </div>
                    )}
                  </div>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </Link>
    );
  };

  // If content is provided, parse it and use the shared template
  if (content) {
    // Extract author data from simple HTML content
    // The content format is: <p>Name<br>Credentials<br>Field<br>Country<br>ImagePath</p>
    const lines = content.replace(/<\/?p>/g, '').split('<br>').map(line => line.trim());

    let authorImage: string | null = null;
    let authorName: string = '';
    let credentials: string = '';
    let field: string = '';
    let country: string = '';

    // Parse the lines
    if (lines.length >= 1) authorName = lines[0] || '';
    if (lines.length >= 2) credentials = lines[1] || '';
    if (lines.length >= 3) field = lines[2] || '';
    if (lines.length >= 4) country = lines[3] || '';

    // Look for image path (should be the last line and start with /)
    if (lines.length > 0) {
      const lastLine = lines[lines.length - 1];
      if (lastLine && lastLine.startsWith('/')) {
        authorImage = lastLine;
      }
    }

    return renderAuthorTemplate(authorName, credentials, country, field, authorImage);
  }

  // Return null if no author information
  if (!author?.author_name) return null;

  // For metadata-based authors, use the shared template
  return renderAuthorTemplate(
    author.author_name,
    author.credentials || '',
    author.author_country || '',
    '', // No field in metadata-based version
    author.avatar || null
  );
}

// app/components/BadgeSymbol/BadgeSymbol.tsx
"use client";

import React from "react";
import "./styles.css"; // Import the styles

export interface BadgeSymbolData {
  symbol: string;
  materialType?: string;
  atomicNumber?: number;
  formula?: string;
  description?: string;
}

interface BadgeSymbolProps {
  content: string;
  config?: BadgeSymbolData & {
    variant?: "card" | "large" | "small";
    className?: string;
  };
}

export function BadgeSymbol({ content, config }: BadgeSymbolProps) {
  if (!config) return null;

  const { 
    symbol, 
    materialType, 
    atomicNumber, 
    formula, 
    variant = "card", 
    className = "" 
  } = config;

  // If no symbol is provided, don't render
  if (!symbol) {
    return null;
  }

  // Format symbol with proper case and limit to 3 characters following chemical symbol conventions
  function formatSymbol(input?: string): string {
    if (!input) return "";

    // Limit to 3 characters
    const limitedSymbol = input.substring(0, 3);

    // Handle chemical symbol conventions:
    // - Single-letter symbols are uppercase (H, C, O)
    // - Multi-letter symbols have first letter uppercase, rest lowercase (He, Al, Si, Fe)
    // - Two-letter standard element symbols never have both letters uppercase
    if (limitedSymbol.length === 1) {
      return limitedSymbol.toUpperCase();
    } else {
      // For two or more letters, capitalize first letter only
      return (
        limitedSymbol.charAt(0).toUpperCase() +
        limitedSymbol.slice(1).toLowerCase()
      );
    }
  }

  // Format the symbol for display
  const displaySymbol = formatSymbol(symbol);

  // Determine if we have a complex formula that needs special handling
  const isComplexFormula =
    displaySymbol.length > 2 || /[0-9]/.test(displaySymbol);

  // Configure sizes based on variant and complexity
  const sizeConfig = {
    card: {
      container: isComplexFormula ? "w-12 h-12" : "w-8 h-8",
      symbol: isComplexFormula ? "text-lg" : "text-md",
      number: "text-xs"
    },
    large: {
      container: isComplexFormula ? "w-16 h-16" : "w-14 h-14",
      symbol: isComplexFormula ? "text-xl" : "text-2xl",
      number: "text-sm"
    },
    small: {
      container: isComplexFormula ? "w-8 h-8" : "w-7 h-7",
      symbol: isComplexFormula ? "text-sm" : "text-base",
      number: "text-[8px]"
    },
  };

  // Default text colors - consistent styling
  const textColorConfig = {
    default: "text-gray-100 font-semibold", // Light text for red background
    number: "text-gray-200 font-bold"
  };

  // Utility function to format chemical formula with subscripts
  const formatChemicalFormula = (formula: string): string => {
    return formula.replace(/([0-9]+)/g, "<sub>$1</sub>");
  };

  const sizes = sizeConfig[variant];

  // Build className parts separately for better maintainability
  const containerClasses = [
    sizes.container,
    "bg-red-900", // Red background for visibility
    "rounded-md border border-red-800",
    "flex flex-col items-center justify-center",
    "shadow-sm",
    "badge-container", // Add our custom class for z-index
    className
  ].join(" ");

  return (
    <div className={`badge-symbol ${containerClasses}`}>
      {/* Atomic number if available */}
      {atomicNumber && (
        <span className={`${sizes.number} ${textColorConfig.number} badge-content`}>
          {atomicNumber}
        </span>
      )}

      {/* Symbol or Formula - Use subscripts for numbers in formulas */}
      <span
        className={`${sizes.symbol} ${textColorConfig.default} leading-tight badge-content`}
      >
        {isComplexFormula ? (
          <span
            dangerouslySetInnerHTML={{
              __html: formatChemicalFormula(displaySymbol),
            }}
          />
        ) : (
          displaySymbol
        )}
      </span>

      {/* Debug info - will be hidden in production */}
      {process.env.NODE_ENV === 'development' && (
        <span className="hidden">{`Symbol: ${symbol}, Formula: ${formula}`}</span>
      )}
    </div>
  );
}

// app/components/Card/Card.tsx
"use client";

import "./styles.scss";
import Link from "next/link";
import { Thumbnail } from "../Thumbnail/Thumbnail";
import { BadgeSymbol } from "../BadgeSymbol/BadgeSymbol";

// Global card configuration with a single variant
const CARD_CONFIG = {
  // Layout
  padding: "p-2",
  imageHeight: "aspect-[16/9] h-20", // Combine aspect ratio with min-height

  // Typography
  titleClass:
    "text-lg font-semibold group-hover:text-blue-600 transition-colors duration-200",
  descriptionClass:
    "text-gray-600 dark:text-gray-300 text-sm line-clamp-2",

  // Appearance
  cardClass:
    "rounded-lg shadow-md hover:shadow-xl transition-all duration-300 overflow-hidden border border-gray-100 dark:bg-gray-800 dark:border-gray-700",
};

// New standardized interface for badge data
interface BadgeData {
  symbol?: string;
  atomicNumber?: number | string;
  formula?: string;
  materialType?: string;
  color?: string;
  show?: boolean; // Added for simplified flag
}

export interface CardProps {
  href: string;
  title: string;
  name?: string;
  description?: string;
  image?: string;
  imageUrl?: string;
  imageAlt?: string;
  materialSlug?: string; // Add materialSlug for hero images
  tags?: string[];
  badge?: BadgeData | null; // Allow null
  metadata?: {
    title?: string;
    name?: string;
    description?: string;
    category?: string;
    subject?: string;
    article_type?: string;
    articleType?: string;
    keywords?: string[];
    tags?: string[];
    date?: string;
    author?: string;
    image?: string;
    thumbnail?: string;
    showBadge?: boolean;
    badge?: {
      text?: string;
      variant?: string;
      color?: string;
    };
  };
  className?: string;
  height?: string;
}

export function Card({
  href,
  title,
  name,
  // description, - unused
  // image, - unused  
  // imageUrl, - unused
  imageAlt,
  // materialSlug, - unused
  // tags = [], - unused
  badge, // Re-enabled for BadgeSymbol support
  metadata,
  className = "",
  height,
}: CardProps) {
  // Extract slug from href (e.g., "/materials/silicon-nitride" -> "silicon-nitride")
  const slug = href?.split('/').pop() || '';

  // For frontmatter files, we need to handle the path correctly
  // const isFrontmatterPath = (path: string | undefined) => {
  //   return path && path.includes('content/components/frontmatter/');
  // };

  // Determine material slug for image - use passed materialSlug, or extract from metadata.subject or slug
  // const effectiveMaterialSlug = 
  //   // If materialSlug is a frontmatter path, use it directly
  //   (materialSlug && isFrontmatterPath(materialSlug)) ? materialSlug :
  //   // Otherwise use the normal options
  //   materialSlug || 
  //   (metadata?.subject ? metadata.subject.toLowerCase() : null) || 
  //   (slug.includes('-') ? slug.split('-')[0].toLowerCase() : slug.toLowerCase());

  // Check if this is a featured card by examining the className
  const isFeatured = className?.includes('featured-item');

  return (
    <Link
      href={href}
      className={`
        group block ${CARD_CONFIG.cardClass} h-full ${className}
      `}
      style={height ? { height } : {}}
    >
      <article className="flex flex-col h-full">
        {/* Image Container with dynamic height based on featured status */}
        <div
          className={`relative w-full ${CARD_CONFIG.imageHeight} overflow-hidden bg-gray-50 dark:bg-gray-800 card-image-container`}
        >
          <Thumbnail
            alt={imageAlt || name || title || (metadata?.subject ? metadata.subject : 'Image')}
            slug={slug}
            objectFit="cover"
            priority={false}
          />

          {/* BadgeSymbol overlay for cards */}
          {badge && badge.symbol && (
            <div className="absolute top-2 right-2 z-10">
              <BadgeSymbol
                content=""
                config={{
                  symbol: badge.symbol,
                  materialType: badge.materialType,
                  atomicNumber: typeof badge.atomicNumber === 'number' ? badge.atomicNumber : 
                               typeof badge.atomicNumber === 'string' ? parseInt(badge.atomicNumber) : undefined,
                  formula: badge.formula,
                  variant: "card"
                }}
              />
            </div>
          )}
        </div>

        {/* Card Content */}
        <div className={`${CARD_CONFIG.padding} flex-grow flex flex-col`}>
          <h3 className={CARD_CONFIG.titleClass}>
            {/* Prioritize name over title */}
            {name || title}
          </h3>

        </div>
      </article>
    </Link>
  );
}

// app/components/Layout/Layout.tsx
import { Content } from "../Content/Content";
import { Table } from "../Table/Table";
import { PropertiesTable } from "../PropertiesTable";
import { Bullets } from "../Bullets/Bullets";
import { Caption } from "../Caption/Caption";
import { Tags } from "../Tags/Tags";
import { Author } from '../Author/Author';
import { JsonLD, schemas } from '../JsonLD/JsonLD';
import { Hero } from '../Hero/Hero';
import { Title } from '../Title/Title';
import { BadgeSymbol } from '../BadgeSymbol/BadgeSymbol';

// Update component order to include propertiestable and tags
const COMPONENT_ORDER = [
  'propertiestable',
  'author',
  'badgesymbol',
  'content',
  'caption',
  'bullets',
  'table',
  'tags'  
] as const;

interface LayoutProps {
  components: Record<string, any> | null; // Keep any for component flexibility
  metadata?: any; // Keep any for metadata flexibility
  slug?: string;
  title?: string;
  hideHeader?: boolean;
  className?: string;
}

export function Layout({ 
  components, 
  metadata, 
  slug,
  title,
  hideHeader = false,
  className = "max-w-4xl mx-auto px-4 py-8"
}: LayoutProps) {
  // Determine the title to display with improved hierarchy
  const displayTitle = title || metadata?.title || metadata?.headline || metadata?.subject || (slug ? `Article: ${slug}` : '');

  // Determine the subtitle to display
  const displaySubtitle = metadata?.title ? metadata?.headline : metadata?.description;

  // Extract material name for hero image (from subject or slug)
  const materialName = metadata?.subject?.toLowerCase() || 
    (slug?.includes('-') ? slug.split('-')[0].toLowerCase() : slug?.toLowerCase());

  // Generate JSON-LD if we have enough metadata
  const jsonLdData = metadata?.title && metadata?.description ? 
    schemas.technicalArticle({
      headline: metadata.title,
      description: metadata.description,
      author: metadata.author || 'Z-Beam',
      datePublished: metadata.datePublished || new Date().toISOString().split('T')[0],
      dateModified: metadata.dateModified,
      url: metadata.canonical || `https://z-beam.com/${slug}`,
      image: metadata.ogImage,
      keywords: metadata.keywords
    }) : null;

  return (
    <section className={className}>
      {/* Only include JSON-LD here, not other meta tags */}
      {jsonLdData && <JsonLD data={jsonLdData} />}

      {/* Add Hero component (now just for background image) */}
      {!hideHeader && materialName && (
        <Hero
          frontmatter={metadata}
          theme="dark"
          align="center"
        />
      )}

      {/* Render components in specified order */}
      {components && COMPONENT_ORDER.map(type => {
        if (!components[type]) return null;

        const { content, config } = components[type];

        switch(type) {
          case 'propertiestable':
            return (
              <div key={type}>
                <PropertiesTable content={content} config={config} />
                {/* Add Title component after PropertiesTable */}
                {!hideHeader && displayTitle && (
                  <Title subtitle={displaySubtitle}>
                    {displayTitle}
                  </Title>
                )}
              </div>
            );
          case 'author':
            return <Author key={type} content={content} config={config} />;
          case 'badgesymbol':
            return <BadgeSymbol key={type} content={content} config={config} />;
          case 'content':
            return <Content key={type} content={content} config={config} />;
          case 'caption':
            return <Caption key={type} content={content} frontmatter={metadata} config={config} />;
          case 'bullets':
            return <Bullets key={type} content={content} config={config} />;
          case 'table':
            return <Table key={type} content={content} config={config} />;
          case 'tags':
            return <Tags key={type} content={content} config={config} />;
          default:
            return null;
        }
      })}
    </section>
  );
}

