  slugs,
  items,
  title,
  heading,
  columns = 3,
  filterBy = "all",
  className = "",
}: ListProps) {
  // Use heading for title
  const displayTitle = title || heading;

  // Process items from either slugs or items prop
  const processedItems = items || [];

  // If slugs are provided but not items, create items from slugs
  if (slugs && !items) {
    const slugItems = slugs.map((slug) => ({ slug }));
    processedItems.push(...slugItems);
  }

  // Fetch articles - Update the return object structure
  const articles = await Promise.all(
    processedItems.map(async (item) => {
      const article = (await getArticle(item.slug)) as Article | null;

      // Create badge object with proper structure
      const badgeText = item.badge || article?.metadata?.category;
      const badgeObject = badgeText
        ? {
            text: badgeText,
            color: getCategoryColor(article?.metadata?.category),
          }
        : undefined;

      // Determine image with fallbacks
      const imageUrl = getArticleImage(item, article);

      // Extract chemical data from article
      let chemicalSymbol = article?.metadata?.chemicalSymbol;
      const atomicNumber = article?.metadata?.atomicNumber;
      let chemicalFormula = article?.metadata?.chemicalFormula;

      // If not directly in metadata, try to get from properties
      if (!chemicalFormula && article?.metadata?.properties?.chemicalFormula) {
        chemicalFormula = article.metadata.properties.chemicalFormula;
      }

      // If we have a formula but no symbol, extract symbol from formula or name
      if (chemicalFormula && !chemicalSymbol) {
        // Extract first element from formula (e.g., "Al" from "Al₂O₃")
        const match = chemicalFormula.match(/([A-Z][a-z]?)/);
        chemicalSymbol = match
          ? match[0]
          : article?.metadata?.subject?.substring(0, 2) || "";
      }

      // Load BadgeSymbol data from content/components/badgesymbol/
      let badgeSymbolData: {
        symbol: string;
        materialType?: string;
        atomicNumber?: number;
        formula?: string;
      } | null = null;
      try {
        const badgeSymbol = await loadComponent('badgesymbol', item.slug);
        if (badgeSymbol?.config) {
          const config = badgeSymbol.config as any; // Type assertion for flexibility
          const symbolValue = config.symbol || chemicalSymbol;
          if (symbolValue) {
            badgeSymbolData = {
              symbol: String(symbolValue),
              materialType: config.materialType ? String(config.materialType) : article?.metadata?.category as string,
              atomicNumber: config.atomicNumber ? Number(config.atomicNumber) : atomicNumber,
              formula: config.formula ? String(config.formula) : chemicalFormula,
            };
          }
        }
      } catch (error) {
        // If no BadgeSymbol content file exists, fall back to article metadata
        if (chemicalSymbol) {
          badgeSymbolData = {
            symbol: chemicalSymbol,
            materialType: article?.metadata?.category as string,
            atomicNumber: atomicNumber,
            formula: chemicalFormula,
          };
        }
      }

      return {
        slug: item.slug,
        title: article?.metadata?.subject || item.title || item.slug,
        description: article?.metadata?.description || item.description || "",
        badge: badgeObject,
        imageUrl: imageUrl,
        category: article?.metadata?.category || "",
        articleType: article?.metadata?.articleType || "",
        // Add these properties directly to the item
        chemicalSymbol,
        atomicNumber,
        chemicalFormula,
        // Pass the featured flag
        featured: item.featured,
        // Pass the full article for other needs
        materialData: article,
        // Pass the loaded BadgeSymbol data
        badgeSymbolData,
      };
    })
  );

  // Filter articles
  const filteredItems =
    filterBy === "all"
      ? articles
      : articles.filter((a) => a.articleType === filterBy);

  const gridCols = {
    1: "grid-cols-1",
    2: "grid-cols-2 md:grid-cols-2",
    3: "grid-cols-2 md:grid-cols-2 lg:grid-cols-3",
    4: "grid-cols-2 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4",
  };

  if (!filteredItems?.length) return null;

  return (
    <div className={`list-section ${className}`}>
      {displayTitle && <h2 className="list-title">{displayTitle}</h2>}

      <div className={`grid gap-4 ${gridCols[columns]}`}>
        {filteredItems.map((item) => {
          // We'll still hide the BadgeSymbol for featured items
          const isFeatured = item.featured;

          return (
            <Card
              key={item.slug}
              title={item.title}
              description={item.description}
              href={`/${item.slug}`}
              badge={item.badgeSymbolData || {
                symbol: item.chemicalSymbol,
                formula: item.chemicalFormula,
                atomicNumber: item.atomicNumber,
                materialType: item.category,
              }}
              imageUrl={item.imageUrl}
              imageAlt={item.title}
              metadata={item.materialData?.metadata || {
                category: item.category,
                articleType: item.articleType,
              }}
              height={isFeatured ? "auto" : undefined}
            />
          );
        })}
      </div>
    </div>
  );
}

// Helper function to get article image with fallbacks
function getArticleImage(
  item: { slug: string; image?: string },
  article: Article | null
): string | undefined {
  // First, try to use the directly provided image
  if (item.image) return item.image;

  // Then, try to get the image from the article metadata
  const metadataImage = article?.metadata?.image;
  if (metadataImage) return metadataImage;

  // Try to get OpenGraph image from metadata if available
  const ogImage =
    article?.metadata?.["ogImage"] ||
    (article?.metadata as any)?.["openGraph"]?.["images"]?.[0]?.["url"];
  if (ogImage) return ogImage;

  // Return undefined to let the Thumbnail component handle all fallbacks
  return undefined;
}

// Helper function to map categories to colors
function getCategoryColor(
  category?: string
): "blue" | "green" | "purple" | "orange" | undefined {
  if (!category) return undefined;

  const categoryColors: Record<string, "blue" | "green" | "purple" | "orange"> =
    {
      material: "blue",
      application: "green",
      technique: "purple",
      industry: "orange",
      // Add more mappings as needed
    };

  return categoryColors[category.toLowerCase()] || "blue"; // Default to blue
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { SearchResultsGrid } from "./SearchResultsGrid";
import { SearchHeader } from "./SearchHeader";
import { SearchResultsCount } from "./SearchResultsCount";
import { EmptySearchResults } from "./EmptySearchResults";
import { /* Article, */ EnrichedArticle } from "../../types/Article";

interface SearchResultsProps {
  items: EnrichedArticle[];
  initialTag?: string;
  placeholder?: string;
  columns?: 1 | 2 | 3 | 4;
  className?: string;
  showTagFilter?: boolean;
}

export function SearchResults({
  items,
  initialTag = "",
  placeholder = "Search materials, articles, and more...",
  columns = 3,
  className = "",
  showTagFilter = true,
}: SearchResultsProps) {
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedTag, setSelectedTag] = useState("");

  // Extract all unique tags from the items
  const allTags = useMemo(() => {
    const tagSet = new Set<string>();

    items.forEach(item => {
      if (item.tags && Array.isArray(item.tags)) {
        item.tags.forEach(tag => {
          if (tag) tagSet.add(tag);
        });
      }
    });

    return Array.from(tagSet).sort();
  }, [items]);

  // Set initial tag from prop
  useEffect(() => {
    if (initialTag) {
      // Decode and normalize the initial tag
      const decodedTag = decodeURIComponent(initialTag)
        .replace(/\+/g, ' ')
        .trim();

      // Check if this tag exists in our items
      const tagExists = items.some(item => 
        item.tags && item.tags.some(t => t.toLowerCase() === decodedTag.toLowerCase())
      );

      // Try finding a capitalized version of the tag if it exists in our items
      if (!tagExists && decodedTag) {
        const allItemTags = new Set<string>();
        items.forEach(item => {
          if (item.tags) {
            item.tags.forEach(tag => {
              if (tag) allItemTags.add(tag);
            });
          }
        });

        // Find the tag with the matching lowercase form
        const matchingTag = Array.from(allItemTags).find(
          tag => tag.toLowerCase() === decodedTag.toLowerCase()
        );

        if (matchingTag) {
          setSelectedTag(matchingTag); // Use the version that exists in the items
          return;
        }
      }

      setSelectedTag(decodedTag);
    }
  }, [initialTag, items]);

  // Simple tag matching function
  function itemMatchesTag(item: any, tag: string): boolean {
    if (!tag) return true;
    if (!item.tags || !Array.isArray(item.tags)) return false;

    const tagLower = tag.toLowerCase();

    // Enhanced matching logic for tags
    const hasMatch = item.tags.some((t: string) => {
      if (!t) return false;

      // Direct match (case-insensitive)
      if (t.toLowerCase() === tagLower) return true;

      return false;
    });

    return hasMatch;
  }

  // Count items matching each tag
  const tagItemCounts = useMemo(() => {
    const counts: Record<string, number> = {};

    // Initialize all tags with zero count
    allTags.forEach(tag => {
      counts[tag] = 0;
    });

    // Count items for each tag
    items.forEach(item => {
      allTags.forEach(tag => {
        if (itemMatchesTag(item, tag)) {
          counts[tag] = (counts[tag] || 0) + 1;
        }
      });
    });

    return counts;
  }, [items, allTags]);

  // Filter to only show tags that have at least one matching item
  const filteredTags = useMemo(() => {
    return allTags.filter(tag => tagItemCounts[tag] > 0);
  }, [allTags, tagItemCounts]);

  // Simple search matching function
  function itemMatchesSearch(item: EnrichedArticle, query: string): boolean {
    if (!query) return true;

    const queryLower = query.toLowerCase();

    return (
      // Title
      (item.title && item.title.toLowerCase().includes(queryLower)) ||
      // Description
      (item.description && item.description.toLowerCase().includes(queryLower)) ||
      // Frontmatter title
      (item.frontmatter?.title && item.frontmatter.title.toLowerCase().includes(queryLower)) ||
      // Frontmatter description
      (item.frontmatter?.description && item.frontmatter.description.toLowerCase().includes(queryLower)) ||
      // Author (both direct and frontmatter)
      (item.author && typeof item.author === 'string' && item.author.toLowerCase().includes(queryLower)) ||
      (item.frontmatter?.author && typeof item.frontmatter.author === 'string' && item.frontmatter.author.toLowerCase().includes(queryLower)) ||
      // Tags
      (item.tags && item.tags.some(tag => tag.toLowerCase().includes(queryLower)))
    );
  }

  // Filter items based on search query and selected tag
  const filteredItems = useMemo(() => {
    return items.filter(item => 
      itemMatchesSearch(item, searchQuery) && 
      itemMatchesTag(item, selectedTag)
    );
  }, [items, searchQuery, selectedTag]);

  return (
    <div className={`space-y-6 ${className}`}>
      {/* Search header */}
      <SearchHeader
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        tags={filteredTags}
        selectedTag={selectedTag}
        onTagSelect={setSelectedTag}
        placeholder={placeholder}
        showTagFilter={showTagFilter}
        tagItemCounts={tagItemCounts}
      />

      {/* Results count */}
      <SearchResultsCount
        count={filteredItems.length}
        selectedTag={selectedTag || undefined}
        searchQuery={searchQuery || undefined}
      />

      {/* Results grid or empty state */}
      {filteredItems.length > 0 ? (
        <SearchResultsGrid 
          items={filteredItems} 
          columns={columns} 
        />
      ) : (
        <EmptySearchResults />
      )}
    </div>
  );
}

