// app/utils/formatting.ts
// Text and date formatting utilities

export function formatDate(date: string): string {
  return new Intl.DateTimeFormat('en-US', {
    month: 'long',
    day: 'numeric',
    year: 'numeric',
  }).format(new Date(date));
}

export function slugify(str: string): string {
  return str
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '-')
    .replace(/&/g, '-and-')
    .replace(/[^\w\-]+/g, '')
    .replace(/\-\-+/g, '-');
}

export function truncateText(text: string, maxLength: number): string {
  if (text.length <= maxLength) return text;
  return text.substring(0, maxLength).trim() + '...';
}

export function capitalizeFirst(str: string): string {
  if (!str) return str;
  return str.charAt(0).toUpperCase() + str.slice(1);
}

export function kebabToTitle(kebabStr: string): string {
  return kebabStr
    .split('-')
    .map(word => capitalizeFirst(word))
    .join(' ');
}

// Additional utility functions

/**
 * Formats a relative date (e.g., "2 days ago", "3 months ago")
 */
export function formatRelativeDate(date: string): string {
  const now = new Date();
  const targetDate = new Date(date);
  const diffInMs = now.getTime() - targetDate.getTime();
  const diffInDays = Math.floor(diffInMs / (1000 * 60 * 60 * 24));

  if (diffInDays === 0) return 'Today';
  if (diffInDays === 1) return 'Yesterday';
  if (diffInDays < 7) return `${diffInDays} days ago`;
  if (diffInDays < 30) return `${Math.floor(diffInDays / 7)} weeks ago`;
  if (diffInDays < 365) return `${Math.floor(diffInDays / 30)} months ago`;
  return `${Math.floor(diffInDays / 365)} years ago`;
}

/**
 * Removes HTML tags from a string
 */
export function stripHtml(html: string): string {
  return html.replace(/<[^>]*>/g, '');
}

/**
 * Converts text to sentence case
 */
export function toSentenceCase(str: string): string {
  if (!str) return str;
  return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
}

/**
 * Validates if a string is a valid URL
 */
export function isValidUrl(string: string): boolean {
  try {
    new URL(string);
    return true;
  } catch (_) {
    return false;
  }
}

/**
 * Formats file size in human readable format
 */
export function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

// app/utils/frontmatterLoader.ts
import fs from 'fs';
import path from 'path';
import { safeMatterParse } from './yamlSanitizer';
import { logger } from './logger';

export async function loadFrontmatterData(slug: string): Promise<any> {
  try {
    const frontmatterPath = path.join(
      process.cwd(),
      'content',
      'components',
      'frontmatter',
      `${slug}.md`
    );

    if (!fs.existsSync(frontmatterPath)) {
      return null;
    }

    const fileContent = fs.readFileSync(frontmatterPath, 'utf8');

    // Simple approach: Try to parse with gray-matter
    try {
      const { data } = safeMatterParse(fileContent);

      // Direct regex extraction for images even if gray-matter worked
      const heroImageMatch = fileContent.match(/hero:[\s\S]*?url:[\s]*([^\n"]+)/);
      if (heroImageMatch && heroImageMatch[1]) {
        const heroUrl = heroImageMatch[1].trim().replace(/"/g, '');

        // Make sure the images structure exists
        if (!data.images) data.images = {};
        if (!data.images.hero) data.images.hero = {};

        // Add or update the URL
        data.images.hero.url = heroUrl;
      }

      return data;
    } catch (matterError) {
      // Alternative: Extract image URLs directly with regex
      const result: any = {};

      // Extract hero image URL
      const heroImageMatch = fileContent.match(/hero:[\s\S]*?url:[\s]*([^\n"]+)/);
      if (heroImageMatch && heroImageMatch[1]) {
        const heroUrl = heroImageMatch[1].trim().replace(/"/g, '');
        result.images = {
          hero: {
            url: heroUrl
          }
        };
      }

      return result;
    }
  } catch (error) {
    logger.error(`Error loading frontmatter for ${slug}`, error, { slug });
    return null;
  }
}

// app/utils/helpers.ts
// Common helper functions for React components and app logic

import { ComponentVariant, ComponentSize } from '../types';

/**
 * Combines multiple class names, filtering out falsy values
 */
export function cn(...classes: (string | undefined | null | boolean)[]): string {
  return classes.filter(Boolean).join(' ');
}

/**
 * Creates CSS class string based on variant and size
 */
export function getVariantClasses(
  variant: ComponentVariant = 'primary',
  size: ComponentSize = 'md'
): string {
  const variantClasses = {
    primary: 'bg-blue-600 text-white hover:bg-blue-700',
    secondary: 'bg-gray-200 text-gray-900 hover:bg-gray-300',
    outline: 'border border-gray-300 text-gray-700 hover:bg-gray-50',
    ghost: 'text-gray-600 hover:bg-gray-100',
  };

  const sizeClasses = {
    sm: 'px-2 py-1 text-sm',
    md: 'px-4 py-2 text-base',
    lg: 'px-6 py-3 text-lg',
    xl: 'px-8 py-4 text-xl',
  };

  return cn(variantClasses[variant], sizeClasses[size]);
}

/**
 * Generates a consistent image alt text for materials
 */
export function generateMaterialAltText(
  materialName: string,
  context: 'hero' | 'thumbnail' | 'card' = 'card'
): string {
  const contextMap = {
    hero: `Hero image of ${materialName} laser cleaning process`,
    thumbnail: `Thumbnail showing ${materialName} laser cleaning`,
    card: `${materialName} laser cleaning material card`,
  };

  return contextMap[context];
}

/**
 * Safely access nested object properties
 */
export function safeGet<T>(obj: any, path: string, defaultValue: T): T {
  const keys = path.split('.');
  let result = obj;

  for (const key of keys) {
    if (result == null || typeof result !== 'object') {
      return defaultValue;
    }
    result = result[key];
  }

  return result ?? defaultValue;
}

/**
 * Debounce function to limit function calls
 */
export function debounce<T extends (...args: any[]) => any>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  let timeoutId: NodeJS.Timeout;

  return (...args: Parameters<T>) => {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func(...args), delay);
  };
}

/**
 * Throttle function to limit function execution rate
 */
export function throttle<T extends (...args: any[]) => any>(
  func: T,
  limit: number
): (...args: Parameters<T>) => void {
  let inThrottle: boolean;

  return (...args: Parameters<T>) => {
    if (!inThrottle) {
      func(...args);
      inThrottle = true;
      setTimeout(() => (inThrottle = false), limit);
    }
  };
}

/**
 * Creates a delay function for async operations
 */
export function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Checks if code is running in browser environment
 */
export function isBrowser(): boolean {
  return typeof window !== 'undefined';
}

/**
 * Checks if user prefers reduced motion
 */
export function prefersReducedMotion(): boolean {
  if (!isBrowser()) return false;
  return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}

/**
 * Generates a unique ID for components
 */
export function generateId(prefix: string = 'id'): string {
  return `${prefix}-${Math.random().toString(36).substr(2, 9)}`;
}

/**
 * Converts a file to base64
 */
export function fileToBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
}

/**
 * Gets the contrast ratio for accessibility
 */
export function getContrastRatio(hex1: string, hex2: string): number {
  // Simplified contrast ratio calculation
  const getLuminance = (hex: string) => {
    const rgb = parseInt(hex.slice(1), 16);
    const r = (rgb >> 16) & 0xff;
    const g = (rgb >> 8) & 0xff;
    const b = (rgb >> 0) & 0xff;
    return 0.2126 * r + 0.7152 * g + 0.0722 * b;
  };

  const lum1 = getLuminance(hex1);
  const lum2 = getLuminance(hex2);
  const brightest = Math.max(lum1, lum2);
  const darkest = Math.min(lum1, lum2);

  return (brightest + 0.05) / (darkest + 0.05);
}

// app/utils/logger.ts
// Centralized logging utility for the application

export interface LogContext {
  [key: string]: any;
}

export class Logger {
  private isDevelopment = process.env.NODE_ENV === 'development';

  error(message: string, error?: any, context?: LogContext) {
    if (this.isDevelopment) {
      console.error(`[ERROR] ${message}`, error, context);
    }
    // In production, you could send to external logging service
    // e.g., Sentry, LogRocket, etc.
  }

  warn(message: string, context?: LogContext) {
    if (this.isDevelopment) {
      console.warn(`[WARN] ${message}`, context);
    }
  }

  info(message: string, context?: LogContext) {
    if (this.isDevelopment) {
      console.info(`[INFO] ${message}`, context);
    }
  }

  debug(message: string, context?: LogContext) {
    if (this.isDevelopment) {
      console.debug(`[DEBUG] ${message}`, context);
    }
  }
}

export const logger = new Logger();

// Utility function for handling async operations with proper error logging
export const handleAsyncError = async <T>(
  operation: () => Promise<T>,
  fallback: T,
  errorMessage: string
): Promise<T> => {
  try {
    return await operation();
  } catch (error) {
    logger.error(errorMessage, error);
    return fallback;
  }
};

// Error wrapper for content loading operations
export const safeContentOperation = async <T>(
  operation: () => Promise<T>,
  fallback: T,
  operationName: string,
  slug?: string
): Promise<T> => {
  try {
    return await operation();
  } catch (error) {
    logger.error(`Content operation failed: ${operationName}`, error, { slug });
    return fallback;
  }
};

// app/utils/materialBadgeUtils.ts
import { MaterialBadgeData, MaterialType } from '../types/materials';

// Known element symbols mapped to atomic numbers
const ELEMENTS: Record<string, number> = {
  'H': 1, 'He': 2, 'Li': 3, 'Be': 4, 'B': 5, 'C': 6, 'N': 7, 'O': 8,
  'F': 9, 'Ne': 10, 'Na': 11, 'Mg': 12, 'Al': 13, 'Si': 14, 'P': 15,
  'S': 16, 'Cl': 17, 'Ar': 18, 'K': 19, 'Ca': 20, 'Ti': 22, 'Fe': 26,
  'Cu': 29, 'Zn': 30, 'Ag': 47, 'Au': 79, /* Add more as needed */
};

/**
 * Extract material badge data from content
 */
export function getBadgeData(article: any): MaterialBadgeData | null {
  if (!article) return null;

  // Helper function to extract first element symbol from formula
  const extractSymbol = (formula: string): string => {
    const match = formula.match(/([A-Z][a-z]?)/);
    return match ? match[0] : '';
  };

  // Helper to create abbreviation from name
  const abbreviateName = (name: string): string => {
    if (!name) return '';
    return name.substring(0, 2).toUpperCase();
  };

  // 1. Determine material type
  let materialType: MaterialType = 'other';

  if (article.metadata?.properties?.materialType) {
    materialType = article.metadata.properties.materialType as MaterialType;
  } else if (article.metadata?.category) {
    // Map categories to material types
    const category = article.metadata.category.toLowerCase();
    if (category === 'ceramic') materialType = 'ceramic';
    else if (category === 'polymer') materialType = 'polymer';
    else if (category === 'metal' || category === 'alloy') materialType = 'alloy';
    else if (category === 'composite') materialType = 'composite';
  }

  // 2. Extract chemical symbol
  let symbol = article.metadata?.chemicalSymbol;

  // 3. Try to get chemical formula
  let formula = article.metadata?.chemicalFormula;
  if (!formula && article.metadata?.properties?.chemicalFormula) {
    formula = article.metadata.properties.chemicalFormula;
  }
  if (!formula && article.metadata?.composition?.[0]?.formula) {
    formula = article.metadata.composition[0].formula;
  }

  // 4. Get atomic number for elements
  let atomicNumber = article.metadata?.atomicNumber;
  if (!atomicNumber && symbol && ELEMENTS[symbol]) {
    atomicNumber = ELEMENTS[symbol];
  }

  // 5. If we have formula but no symbol, extract from formula
  if (formula && !symbol) {
    symbol = extractSymbol(formula);
  }

  // 6. Last resort: generate symbol from name
  if (!symbol && article.metadata?.subject) {
    symbol = abbreviateName(article.metadata.subject);
  }

  // If we've found nothing, return null
  if (!symbol) return null;

  // Infer material type if still 'other'
  if (materialType === 'other') {
    if (atomicNumber) materialType = 'element';
    else if (formula) materialType = 'compound';
  }

  return {
    symbol,
    formula,
    atomicNumber,
    materialType
  };
}

/**
 * Get gradient style based on material type
 */
export function getMaterialGradient(materialType: MaterialType): string {
  switch (materialType) {
    case 'element':
      return 'bg-gradient-to-br from-blue-500 to-purple-600';
    case 'compound':
    case 'ceramic':
      return 'bg-gradient-to-br from-amber-500 to-red-600';
    case 'polymer':
      return 'bg-gradient-to-br from-green-500 to-teal-600';
    case 'alloy':
      return 'bg-gradient-to-br from-gray-500 to-slate-600';
    case 'composite':
      return 'bg-gradient-to-br from-indigo-500 to-cyan-600';
    default:
      return 'bg-gradient-to-br from-blue-500 to-purple-600';
  }
}

// app/utils/metadata.ts
// Use any type since Metadata isn't being exported correctly from next
type NextMetadata = any;

// Define author interface
export interface AuthorInfo {
  author_id?: number;
  author_name: string;
  author_country?: string;
  credentials?: string;
}

// Update ArticleMetadata to properly type the author field
export interface ArticleMetadata {
  title?: string;
  description?: string;
  keywords?: string[] | string;
  canonical?: string;
  ogImage?: string;
  ogType?: 'website' | 'article' | string; // Allow any string value for ogType
  noindex?: boolean;
  author?: string | AuthorInfo; // Author can be a string or an object
  [key: string]: any; // Allow other properties
}

export function createMetadata(metadata: ArticleMetadata): NextMetadata {

  // Extract all properties safely with defaults
  const {
    title = '',
    description = '',
    keywords = [],
    canonical,
    ogImage,
    ogType = 'article',
    noindex,
    subject,
  } = metadata;

  // Helper function to safely extract author name
  const getAuthorName = (author: string | AuthorInfo | undefined): string | undefined => {
    if (!author) return undefined;
    if (typeof author === 'string') return author;
    return author.author_name;
  };

  // Use subject as title if available and title is not set
  const actualTitle = title || subject || '';

  const formattedTitle = actualTitle && !actualTitle.includes('Z-Beam') 
    ? `${actualTitle} | Z-Beam` 
    : actualTitle || 'Z-Beam';

  const authorName = getAuthorName(metadata.author);

  const result: NextMetadata = {
    title: formattedTitle,
    description: description,
    keywords: Array.isArray(keywords) ? keywords.join(', ') : keywords,
    openGraph: {
      title: actualTitle || formattedTitle,
      description: description,
      type: ogType as 'website' | 'article',
      images: ogImage ? [{ url: ogImage }] : undefined,
      authors: authorName ? [authorName] : undefined,
    },
    alternates: {
      canonical: canonical,
    },
    robots: noindex ? { index: false } : undefined,
  };


  return result;
}

// app/utils/searchUtils.ts
export function getMaterialColor(materialType?: string): string {
  if (!materialType) return "blue";

  const typeMap: Record<string, string> = {
    'metal': 'blue',
    'ceramic': 'green',
    'polymer': 'purple',
    'composite': 'yellow',
    'semiconductor': 'red',
    'compound': 'gray'
  };

  return typeMap[materialType.toLowerCase()] || "blue";
}

export function normalizeString(str?: string): string {
  return (str || "").toLowerCase().trim();
}

export function normalizeTag(tag: string): string {
  if (!tag) return '';

  // Normalize capitalization - capitalize first letter of each word
  return tag
    .trim()
    .split(' ')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
    .join(' ');
}

export function getDisplayName(item: any): string {
  // Try to get the name from different sources in priority order
  if (item.name) return item.name;
  if (item.frontmatter?.name) return item.frontmatter.name;
  if (item.frontmatter?.title) return item.frontmatter.title;
  if (item.title) return item.title;

  // If no name or title, try to create one from the slug
  if (item.slug) {
    return item.slug
      .split('-')
      .map((word: string) => word.charAt(0).toUpperCase() + word.slice(1))
      .join(' ');
  }

  // Last resort
  return "Unnamed Item";
}

export interface BadgeData {
  symbol?: string;
  formula?: string;
  atomicNumber?: number | string;
  materialType?: string;
  color?: string;
}

export interface ChemicalProperties {
  symbol?: string;
  formula?: string;
  materialType?: string;
  atomicNumber?: number | string;
}

export function getBadgeFromItem(item: any): BadgeData | null {
  // If the item already has a badge, use it
  if (item.badge) return item.badge;

  // Extract from frontmatter
  const fm = item.frontmatter || {};

  // Look for subject in frontmatter
  const subject = normalizeString(fm.subject);

  // Special handling for known materials
  if (subject === "alumina") {
    return {
      symbol: "Al",
      formula: "Al₂O₃",
      materialType: fm.category || "ceramic",
      color: getMaterialColor(fm.category)
    };
  }

  if (subject === "silicon nitride") {
    return {
      symbol: "Si",
      formula: "Si₃N₄",
      materialType: fm.category || "ceramic",
      color: getMaterialColor(fm.category)
    };
  }

  // Try to extract from commentMetadata if available
  if (fm.commentMetadata?.Subject) {
    const commentSubject = normalizeString(fm.commentMetadata.Subject);

    if (commentSubject === "alumina") {
      return {
        symbol: "Al",
        formula: "Al₂O₃",
        materialType: fm.category || "ceramic",
        color: getMaterialColor(fm.category)
      };
    }

    if (commentSubject === "silicon nitride") {
      return {
        symbol: "Si",
        formula: "Si₃N₄",
        materialType: fm.category || "ceramic",
        color: getMaterialColor(fm.category)
      };
    }
  }

  // Generic material mapping by category
  if (fm.category) {
    return {
      materialType: fm.category,
      color: getMaterialColor(fm.category)
    };
  }

  // Also check direct category on item
  if (item.category) {
    return {
      materialType: item.category,
      color: getMaterialColor(item.category)
    };
  }

  return null;
}

export function getChemicalProperties(item: any): ChemicalProperties | null {
  // First check if item.metadata already has chemical properties
  if (item.metadata?.chemicalProperties) {
    return item.metadata.chemicalProperties;
  }

  // Otherwise try to extract from frontmatter
  if (item.frontmatter) {
    // Try to find chemical properties in frontmatter
    if (item.frontmatter.chemicalProperties) {
      return item.frontmatter.chemicalProperties;
    }

    // Look for individual chemical properties in frontmatter
    if (item.frontmatter.chemicalSymbol || 
        item.frontmatter.chemicalFormula || 
        item.frontmatter.formula) {
      return {
        symbol: item.frontmatter.chemicalSymbol,
        formula: item.frontmatter.chemicalFormula || item.frontmatter.formula,
        materialType: item.frontmatter.materialType || item.frontmatter.category
      };
    }

    // Try to infer from subject if it's a known material
    if (item.frontmatter.subject) {
      const subject = normalizeString(item.frontmatter.subject);

      if (subject === "alumina") {
        return {
          symbol: "Al",
          formula: "Al₂O₃",
          materialType: item.frontmatter.category || "ceramic"
        };
      }

      if (subject === "silicon nitride") {
        return {
          symbol: "Si",
          formula: "Si₃N₄",
          materialType: item.frontmatter.category || "ceramic"
        };
      }
    }
  }

  return null;
}

// app/utils/tagDebug.ts
// Debug utilities for the tag system
'use server';

import { getArticlesWithTags, getAllTags, getTagCounts } from './tags';
import { loadAllArticles } from './contentAPI';
import { logger } from './logger';

interface TagDebugData {
  totalArticles: number;
  articlesWithAuthor: number;
  articlesWithFrontmatterAuthor: number;
  sampleAuthors: Array<{
    title: string;
    slug: string;
    author: string;
    tags: string[];
  }>;
}

/**
 * Generate comprehensive debug data for the tag system
 */
export async function debugTagSystem(): Promise<TagDebugData> {
  try {
    // Get all articles
    const allArticles = await loadAllArticles();
    const articlesWithTags = await getArticlesWithTags();

    // Count articles with authors
    const articlesWithAuthor = allArticles.filter(article => 
      article.author && typeof article.author === 'string'
    ).length;

    // Count articles with frontmatter author
    const articlesWithFrontmatterAuthor = allArticles.filter(article => 
      article.metadata && article.metadata.author
    ).length;

    // Get sample authors for display
    const sampleAuthors = allArticles
      .filter(article => article.author || article.metadata?.author)
      .slice(0, 10)
      .map(article => ({
        title: article.title || article.slug || 'Unknown',
        slug: article.slug || 'unknown',
        author: getAuthorName(article),
        tags: article.tags || []
      }));

    return {
      totalArticles: allArticles.length,
      articlesWithAuthor,
      articlesWithFrontmatterAuthor,
      sampleAuthors
    };
  } catch (error) {
    logger.error('Error in debugTagSystem', error);

    // Return fallback data
    return {
      totalArticles: 0,
      articlesWithAuthor: 0,
      articlesWithFrontmatterAuthor: 0,
      sampleAuthors: []
    };
  }
}

/**
 * Helper function to extract author name from various article formats
 */
function getAuthorName(article: any): string {
  // Check author object
  if (article.author) {
    if (typeof article.author === 'string') {
      return article.author;
    }
  }

  // Check metadata
  if (article.metadata?.author) {
    if (typeof article.metadata.author === 'string') {
      return article.metadata.author;
    }
  }

  return 'Unknown';
}

/**
 * Get debug information about tag counts and distribution
 */
export async function debugTagCounts(): Promise<{
  totalTags: number;
  topTags: Array<{ tag: string; count: number }>;
  unusedTags: string[];
}> {
  try {
    const allTags = await getAllTags();
    const tagCounts = await getTagCounts();

    // Get top tags
    const topTags = Object.entries(tagCounts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 10)
      .map(([tag, count]) => ({ tag, count }));

    // Find unused tags (count = 0)
    const unusedTags = Object.entries(tagCounts)
      .filter(([, count]) => count === 0)
      .map(([tag]) => tag);

    return {
      totalTags: allTags.length,
      topTags,
      unusedTags
    };
  } catch (error) {
    logger.error('Error in debugTagCounts', error);
    return {
      totalTags: 0,
      topTags: [],
      unusedTags: []
    };
  }
}

/**
 * Debug a specific tag and show which articles match it
 */
export async function debugTag(tagName: string): Promise<{
  tag: string;
  matchCount: number;
  matchingArticles: Array<{
    title: string;
    slug: string;
    tags: string[];
  }>;
}> {
  try {
    const articlesWithTags = await getArticlesWithTags();

    // Find articles that match this tag
    const matchingArticles = articlesWithTags
      .filter(article => 
        article.tags && 
        article.tags.some(tag => 
          tag.toLowerCase() === tagName.toLowerCase()
        )
      )
      .map(article => ({
        title: article.title || article.slug || 'Unknown',
        slug: article.slug || 'unknown',
        tags: article.tags || []
      }));

    return {
      tag: tagName,
      matchCount: matchingArticles.length,
      matchingArticles
    };
  } catch (error) {
    logger.error(`Error in debugTag for ${tagName}`, error);
    return {
      tag: tagName,
      matchCount: 0,
      matchingArticles: []
    };
  }
}

// app/utils/yamlSanitizer.ts
// Utility to sanitize YAML frontmatter and fix common formatting issues

import matter from 'gray-matter';
import { logger } from './logger';

/**
 * Sanitizes YAML frontmatter content to fix common formatting issues
 */
export function sanitizeYamlContent(content: string): string {
  try {
    // Split content into frontmatter and body
    const frontmatterMatch = content.match(/^---\s*\n([\s\S]*?)\n---\s*\n?([\s\S]*)$/);

    if (!frontmatterMatch) {
      return content; // No frontmatter found
    }

    const [, yamlContent, markdownBody] = frontmatterMatch;

    // Fix only specific YAML formatting issues without breaking valid content
    const sanitizedYaml = yamlContent
      // Fix unquoted array values with special characters like [>300°C] -> [">300°C"]
      .replace(/(\[)([^"\]\[]*[>°][^"\]\[]*)(\])/g, (match, openBracket, content, closeBracket) => {
        // Only fix if content contains special characters and isn't already quoted
        if (content.includes('>') || content.includes('°')) {
          const trimmed = content.trim();
          if (!trimmed.startsWith('"') && !trimmed.endsWith('"')) {
            return `${openBracket}"${trimmed}"${closeBracket}`;
          }
        }
        return match;
      });

    return `---\n${sanitizedYaml}\n---\n${markdownBody}`;
  } catch (error) {
    logger.warn('Failed to sanitize YAML content, returning original', { error: (error as Error).message });
    return content;
  }
}

/**
 * Safe wrapper around gray-matter that includes YAML sanitization
 */
export function safeMatterParse(content: string, options?: any): {
  data: { [key: string]: any };
  content: string;
  excerpt: string;
  orig: string;
} {
  try {
    // First try parsing as-is
    const result = matter(content, options);
    return {
      data: result.data,
      content: result.content,
      excerpt: result.excerpt || '',
      orig: String(result.orig || content)
    };
  } catch (error) {
    logger.warn('Initial YAML parsing failed, attempting sanitization', { error: (error as Error).message });

    try {
      // Try with sanitized content
      const sanitizedContent = sanitizeYamlContent(content);
      const result = matter(sanitizedContent, options);
      return {
        data: result.data,
        content: result.content,
        excerpt: result.excerpt || '',
        orig: String(result.orig || content)
      };
    } catch (sanitizationError) {
      logger.error('YAML sanitization failed', sanitizationError);

      // Last resort: try to extract just the markdown content without frontmatter
      try {
        const frontmatterMatch = content.match(/^---\s*\n[\s\S]*?\n---\s*\n?([\s\S]*)$/);
        const markdownContent = frontmatterMatch ? frontmatterMatch[1] : content;

        logger.warn('Falling back to content-only parsing due to YAML errors');

        return {
          data: {},
          content: markdownContent,
          excerpt: '',
          orig: content
        };
      } catch (fallbackError) {
        // Ultimate fallback - return the content as-is
        logger.error('All parsing attempts failed, returning raw content', fallbackError);

        return {
          data: {},
          content: content,
          excerpt: '',
          orig: content
        };
      }
    }
  }
}
